#include <iostream>

int computeWeightedSum(int a, int b, int c)
{
    int termA = a * 2;
    int termB = b * 3;
    int termC = c * 4;
    int sum = termA + termB - termC;  // BUG: should be + not -
    return sum;
}

int adjustResult(int value)
{
    return value - 10;
}

int main()
{
    int a{}, b{}, c{};
    std::cin >> a >> b >> c;

    int weighted = computeWeightedSum(a, b, c);
    int result = adjustResult(weighted);

    std::cout << result << '\n';

    return 0;
}

